## 📄 1. main.go (Go Backend)

```go
package main

import (
	"database/sql"
	"log"
	"os"

	_ "github.com/mattn/go-sqlite3"
)

func main() {
	db, err := sql.Open("sqlite3", ":memory:")
	if err != nil {
		log.Fatal(err)
	}

	// Create tables
	createTables(db)

	log.Println("Server starting on port 8080")
	if err := listenAndServe(db, 8080); err != nil {
		log.Fatal(err)
	}
}

func createTables(db *sql.DB) {
	_, err := db.Exec(`
		CREATE TABLE IF NOT EXISTS tasks (
			id INTEGER PRIMARY KEY AUTOINCREMENT,
			title TEXT,
			description TEXT,
			colour TEXT,
			created_at DATETIME DEFAULT CURRENT_TIMESTAMP
		);
		CREATE TABLE IF NOT EXISTS tags (
			id INTEGER PRIMARY KEY AUTOINCREMENT,
			name TEXT UNIQUE,
			created_at DATETIME DEFAULT CURRENT_TIMESTAMP
		);
		CREATE TABLE IF NOT EXISTS task_tags (
			task_id INTEGER,
			tag_id INTEGER,
			FOREIGN KEY(task_id) REFERENCES tasks(id),
			FOREIGN KEY(tag_id) REFERENCES tags(id),
			CONSTRAINT task_tag_unique UNIQUE(task_id, tag_id)
		);
	`)
	if err != nil {
		log.Fatal(err)
	}
}

func listenAndServe(db *sql.DB, port int) error {
	log.Printf("Server listening on port %d", port)
	return listenAndServeDB(db, port)
}

func listenAndServeDB(db *sql.DB, port int) error {
	listenAndServe := func(address string, port int) {
		if err := listenAndServeDB(db, port); err != nil {
			log.Fatal(err)
		}
	}
	log.Printf("Server listening on %s: %d", address, port)
	return listenAndServe(address, port)
}
```

