## 🧱 3. Frontend (JavaScript)

```javascript
// Frontend logic
const tasks = [];
const columns = [
    { id: 'backlog', name: 'Backlog' },
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' }
];

// Initialize
async function init() {
    const response = await fetch('/api/tasks');
    const tasksData = await response.json();
    tasks = tasksData.tasks;

    columns.forEach(col => {
        const columnId = col.id;
        const columnTasks = tasks.filter(task => task.colour === col.id);

        const columnDiv = document.createElement('div');
        columnDiv.className = 'task-column';
        columnDiv.id = columnId;

        columnDiv.innerHTML = `
            <div class="column-header">${col.name}</div>
            <div class="task-list">
                ${tasks.filter(task => task.colour === col.id).map(task => createTaskElement(task, columnId))}
            </div>
        `;
        document.getElementById('taskList').appendChild(columnDiv);
    });
}

function createTaskElement(task, columnId) {
    const taskDiv = document.createElement('div');
    taskDiv.className = 'task';
    taskDiv.innerHTML = `
        <span class="tag">#${task.id}</span>
        <span>${task.title}</span>
        <span class="tag">#${task.colour}</span>
    `;
    return taskDiv;
}

// Drag and drop
document.querySelectorAll('.task').forEach(task => {
    task.addEventListener('dragstart', (e) => {
        task.classList.add('dragging');
    });

    task.addEventListener('dragend', (e) => {
        task.classList.remove('dragging');
    });
});

// Search functionality
document.getElementById('searchInput').addEventListener('input', (e) => {
    const search = e.target.value.toLowerCase();
    const filteredTasks = tasks.filter(task => task.title.toLowerCase().includes(search));
    document.getElementById('taskList').innerHTML = filteredTasks.map(task => createTaskElement(task, 'todo')).join('');
});
